use std::sync::{Arc, Mutex};

struct Config {
    data: String,
}

impl Config {
    fn new(data: String) -> Self {
        Self { data }
    }
    fn update(&mut self, new_data: String) {
        self.data = new_data;
    }
}

fn main() {
    let config = Arc::new(Mutex::new(Config::new(String::from("initial"))));
    let mut guard = config.lock().unwrap();
    guard.update(String::from("updated"));
}

