fixed_code:
fn parse_input(input: &str) -> Vec<i32> {
    static mut DATA: Option<Vec<i32>> = None;

    unsafe {
        if DATA.is_none() {
            DATA = Some(
                input.split_whitespace()
                    .map(|s| s.parse().unwrap())
                    .collect(),
            );
        }
        DATA.clone().unwrap()
    }
}

fn main() {
    let input = "1 2 3";
    let vec1 = parse_input(input);
    let vec2 = parse_input(input);
}

